import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"3. 管理ダッシュボード","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/03-dashboard.md","filePath":"tenant/03-dashboard.md"}'),o={name:"tenant/03-dashboard.md"};function h(l,t,i,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_3-管理ダッシュボード" tabindex="-1">3. 管理ダッシュボード <a class="header-anchor" href="#_3-管理ダッシュボード" aria-label="Permalink to &quot;3. 管理ダッシュボード&quot;">​</a></h1><p>管理ダッシュボード（dashboard.html）は、マネージャーとスタッフが日常的に使用するメイン画面です。タブで機能を切り替えながら、店舗運営に必要な全ての操作を行います。</p><h2 id="_3-1-画面構成" tabindex="-1">3.1 画面構成 <a class="header-anchor" href="#_3-1-画面構成" aria-label="Permalink to &quot;3.1 画面構成&quot;">​</a></h2><h3 id="ヘッダー" tabindex="-1">ヘッダー <a class="header-anchor" href="#ヘッダー" aria-label="Permalink to &quot;ヘッダー&quot;">​</a></h3><p>画面上部のヘッダーには以下の要素があります。</p><table tabindex="0"><thead><tr><th>位置</th><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>左</td><td>テナント名</td><td>あなたの企業/ブランド名が表示されます</td></tr><tr><td>左</td><td>店舗セレクター</td><td>ドロップダウンで操作対象の店舗を切り替えます。複数店舗に所属している場合に使用します。選択した店舗はブラウザに記憶され、次回アクセス時も同じ店舗が選択されます</td></tr><tr><td>右</td><td>ショートカットリンク</td><td>「ハンディ」「KDS」「レジ」「注文画面」への直接リンク。新しいタブで開きます</td></tr><tr><td>右</td><td>ユーザー名</td><td>現在ログイン中のユーザー名が表示されます</td></tr><tr><td>右</td><td>ログアウトボタン</td><td>クリックでログアウトします</td></tr></tbody></table><h3 id="メインタブ-グループタブ" tabindex="-1">メインタブ（グループタブ） <a class="header-anchor" href="#メインタブ-グループタブ" aria-label="Permalink to &quot;メインタブ（グループタブ）&quot;">​</a></h3><p>ヘッダーの下に、横並びのメインタブが表示されます。タブをクリックすると、対応する機能グループが表示されます。</p><table tabindex="0"><thead><tr><th>タブ名</th><th>対象ロール</th><th>内容</th></tr></thead><tbody><tr><td>メニュー管理</td><td>マネージャー以上</td><td>カテゴリ・メニュー・オプション・限定メニューの管理</td></tr><tr><td>プラン・コース</td><td>マネージャー以上</td><td>食べ放題プラン・コース料理の管理</td></tr><tr><td>テーブル・フロア</td><td>マネージャー以上</td><td>テーブル登録・フロアマップの配置</td></tr><tr><td>在庫・レシピ</td><td>マネージャーのみ</td><td>食材・レシピ・棚卸しの管理（proプラン以上）</td></tr><tr><td>レポート</td><td>マネージャー以上</td><td>売上・レジ・回転率・スタッフ評価・併売分析</td></tr><tr><td>店舗設定</td><td>マネージャー以上</td><td>営業設定・KDSステーション・スタッフ管理・監査ログ・領収書設定</td></tr><tr><td>テイクアウト</td><td>マネージャー以上</td><td>テイクアウト注文の受付・管理（proプラン以上）</td></tr><tr><td>AIアシスタント</td><td>マネージャー以上</td><td>SNS投稿生成・売上分析・競合調査・需要予測</td></tr><tr><td>シフト管理</td><td>スタッフ以上</td><td>シフト管理・勤怠連携（proプラン以上）</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">スタッフが見えるタブ</p><p>スタッフロールでログインした場合、「シフト管理」タブのみが表示されます。その中でも「マイシフト」「希望提出」「勤怠打刻」のみ操作可能で、マネージャー向けのサブタブ（カレンダー、テンプレート、設定、サマリー等）は非表示です。</p></div><h3 id="サブタブ" tabindex="-1">サブタブ <a class="header-anchor" href="#サブタブ" aria-label="Permalink to &quot;サブタブ&quot;">​</a></h3><p>メインタブをクリックすると、その中にサブタブが表示されます。サブタブで具体的な機能を切り替えます。</p><p><strong>例：「メニュー管理」タブのサブタブ</strong></p><table tabindex="0"><thead><tr><th>サブタブ名</th><th>説明</th></tr></thead><tbody><tr><td>カテゴリ管理</td><td>メニューのカテゴリ（前菜、メイン、ドリンク等）を作成・編集</td></tr><tr><td>オプション管理</td><td>トッピング・サイズ等のオプショングループと選択肢を管理</td></tr><tr><td>店舗メニュー</td><td>本部メニューの店舗別カスタマイズ（価格上書き・非表示・品切れ）</td></tr><tr><td>限定メニュー</td><td>その店舗だけのオリジナルメニューを追加</td></tr></tbody></table><p><strong>例：「シフト管理」タブのサブタブ</strong></p><table tabindex="0"><thead><tr><th>サブタブ名</th><th>対象ロール</th><th>説明</th></tr></thead><tbody><tr><td>週間カレンダー</td><td>マネージャー</td><td>シフトの割当・編集を行うメイン画面</td></tr><tr><td>マイシフト</td><td>スタッフ</td><td>自分の確定シフトを閲覧</td></tr><tr><td>希望提出</td><td>スタッフ</td><td>希望シフトの日時を提出</td></tr><tr><td>勤怠一覧</td><td>マネージャー</td><td>全スタッフの出退勤記録一覧</td></tr><tr><td>テンプレート</td><td>マネージャー</td><td>シフトパターン（早番・遅番等）の定義</td></tr><tr><td>シフト設定</td><td>マネージャー</td><td>提出締切日・休憩デフォルト・GPS等の設定</td></tr><tr><td>集計サマリー</td><td>マネージャー</td><td>労働時間・人件費・労基法警告の集計</td></tr><tr><td>ヘルプ</td><td>マネージャー</td><td>他店舗へのスタッフ派遣要請（enterpriseプラン）</td></tr></tbody></table><h3 id="コンテンツエリア" tabindex="-1">コンテンツエリア <a class="header-anchor" href="#コンテンツエリア" aria-label="Permalink to &quot;コンテンツエリア&quot;">​</a></h3><p>サブタブの下に、選択中の機能のコンテンツが表示されます。ここに一覧表・フォーム・グラフ等が描画されます。</p><h3 id="勤怠打刻ボタン-スタッフ専用" tabindex="-1">勤怠打刻ボタン（スタッフ専用） <a class="header-anchor" href="#勤怠打刻ボタン-スタッフ専用" aria-label="Permalink to &quot;勤怠打刻ボタン（スタッフ専用）&quot;">​</a></h3><p>スタッフロールでログインすると、画面のヘッダー付近に<strong>出勤ボタン</strong>と<strong>退勤ボタン</strong>が常時表示されます。これは全てのタブで表示され、いつでも打刻できます。マネージャー・オーナーには表示されません。</p><h2 id="タブの操作" tabindex="-1">タブの操作 <a class="header-anchor" href="#タブの操作" aria-label="Permalink to &quot;タブの操作&quot;">​</a></h2><h3 id="タブの切り替え" tabindex="-1">タブの切り替え <a class="header-anchor" href="#タブの切り替え" aria-label="Permalink to &quot;タブの切り替え&quot;">​</a></h3><ol><li>メインタブ（横並び）をクリックすると、対応するサブタブ群が表示されます</li><li>サブタブをクリックすると、コンテンツエリアの内容が切り替わります</li><li>データは<strong>タブ切り替え時に自動で読み込まれます</strong>。手動リフレッシュは不要です</li></ol><h3 id="店舗の切り替え" tabindex="-1">店舗の切り替え <a class="header-anchor" href="#店舗の切り替え" aria-label="Permalink to &quot;店舗の切り替え&quot;">​</a></h3><p>複数店舗に所属している場合：</p><ol><li>ヘッダーの<strong>店舗セレクター</strong>（ドロップダウン）をクリック</li><li>操作したい店舗を選択</li><li>表示中のデータが選択した店舗のものに自動的に切り替わります</li><li>選択した店舗はブラウザに保存され、次回ログイン時も同じ店舗が選ばれます</li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>店舗を切り替えると、現在表示中のデータ（メニュー、注文、シフト等）は全て切り替え先の店舗のものに変わります。編集中の内容がある場合は、保存してから切り替えてください。</p></div><h3 id="別画面へのショートカット" tabindex="-1">別画面へのショートカット <a class="header-anchor" href="#別画面へのショートカット" aria-label="Permalink to &quot;別画面へのショートカット&quot;">​</a></h3><p>ヘッダー右側のショートカットリンクから、以下の画面を新しいタブで直接開けます。</p><table tabindex="0"><thead><tr><th>リンク名</th><th>遷移先</th><th>用途</th></tr></thead><tbody><tr><td>ハンディ</td><td>/handy/</td><td>ハンディPOS画面（注文入力端末）</td></tr><tr><td>KDS</td><td>/kds/</td><td>キッチンディスプレイ画面</td></tr><tr><td>レジ</td><td>/kds/cashier.html</td><td>POSレジ画面</td></tr><tr><td>注文画面</td><td>/customer/menu.html</td><td>お客さん向けセルフオーダー画面（確認用）</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">これらのリンクは新しいタブで開きます</p><p>管理ダッシュボードを閉じずに、別の画面を同時に操作できます。例えば、ダッシュボードでメニューを編集しながら、別タブでセルフオーダー画面を開いて表示を確認する、といった使い方ができます。</p></div><h3 id="プラン外の機能" tabindex="-1">プラン外の機能 <a class="header-anchor" href="#プラン外の機能" aria-label="Permalink to &quot;プラン外の機能&quot;">​</a></h3><p>契約中のプラン（standard/pro/enterprise）に含まれない機能のタブは自動的に非表示になります。例えば、standardプランではシフト管理タブや在庫管理タブは表示されません。プランのアップグレードについてはオーナーダッシュボードの「契約・プラン」タブから手続きできます。</p>',33)])])}const u=d(o,[["render",h]]);export{p as __pageData,u as default};
